-- 1. 첫 번째 리뷰
SET @rv_bid0 = (SELECT b.bid_idx FROM bid b WHERE b.auction_idx = @la AND b.bidder_idx = 3 LIMIT 1);
VALUES (2, 3, @la, @rv_bid0, '빠른 거래 감사합니다!', '스쿼트 랙 상태 설명과 동일했고 거래도 빠르게 진행되어 매우 만족합니다. 다음에도 거래하고 싶어요!', 5);

-- 2. 두 번째 리뷰
SET @rv_bid1 = (SELECT b.bid_idx FROM bid b WHERE b.auction_idx = @la + 1 AND b.bidder_idx = 2 LIMIT 1);
VALUES (3, 2, @la + 1, @rv_bid1, '요가매트 상태 최고예요', '새것처럼 깨끗하고 생각보다 훨씬 품질이 좋았어요. 강력 추천합니다!', 5);

-- 3. 세 번째 리뷰
SET @rv_bid2 = (SELECT b.bid_idx FROM bid b WHERE b.auction_idx = @la + 3 AND b.bidder_idx = 11 LIMIT 1);
VALUES (5, 11, @la + 3, @rv_bid2, '배드민턴 라켓 잘 받았어요', '거트 상태 정말 좋고 설명과 딱 맞게 왔어요. 만족스러운 거래였습니다.', 4);

-- 4. 네 번째 리뷰
SET @rv_bid3 = (SELECT b.bid_idx FROM bid b WHERE b.auction_idx = @la + 5 AND b.bidder_idx = 10 LIMIT 1);
VALUES (7, 10, @la + 5, @rv_bid3, '러닝화 상태 굿굿', '사진이랑 실물이 거의 같았어요. 배송도 빠르고 포장도 꼼꼼했습니다.', 4);

-- 5. 다섯 번째 리뷰
SET @rv_bid4 = (SELECT b.bid_idx FROM bid b WHERE b.auction_idx = @la + 5 AND b.bidder_idx = 10 LIMIT 1);
VALUES (6, 10, @la + 5, @rv_bid4, '두 번째 구매도 만족!', '이전에도 좋은 거래였는데 이번에도 역시 믿고 살 수 있는 판매자입니다.', 5);


