INSERT INTO board (mem_idx, board_title, board_content, board_ip, board_thumbnail, board_view_count, board_type_idx) VALUES
(3,'주말 풋살 같이 하실 분 계신가요?','대구 남구 쪽에서 주말 저녁에 풋살 같이 할 팀 찾고 있습니다.\n실력보단 재밌게 뛰는 분위기 좋아요. 20~30대 위주면 좋겠습니다.','127.0.0.1',NULL,23,1),
(4,'인조잔디 축구화 추천 좀 해주세요','인조잔디 구장에서만 뛰는데, 발볼 넓은 사람에게 잘 맞는 축구화 있을까요?\n가격은 10만원 전후 생각하고 있어요.','127.0.0.1',NULL,15,1),
(5,'초보도 센터백 해도 될까요?','동호회에서 센터백이 부족하다는데, 축구 완전 초보도 센터백 맡아도 괜찮을까요?\n포지션별 역할 잘 아시는 분 조언 부탁드립니다.','127.0.0.1',NULL,9,1),
(2,'완전 초보인데 골프채 세트 어떤 걸로 시작해야 할까요?','골프 완전 처음인데 입문용 풀세트를 살지, 중고로 아이언만 맞춰갈지 고민 중입니다.\n예산은 70~100 정도 생각하고 있어요. 브랜드나 구성 추천 부탁드려요.','127.0.0.1',NULL,32,4),
(2,'스크린 골프 80대 진입하려면 연습 어떻게 해야 하나요?','현재 스크린 기준 90대 초반 꾸준히 나오고 있고, 드라이버는 그럭저럭인데 아이언이 문제입니다.\n효율적인 연습 루틴 추천해주실 분 계실까요?','127.0.0.1',NULL,18,4),
(2,'레슨 받을 때 이건 꼭 체크해라 하는 포인트 있을까요?','이제 레슨 시작하려고 하는데, 코치님한테 꼭 확인해야 할 포인트(자세, 빈스윙, 영상 촬영 등) 있으면 알려주세요.','127.0.0.1',NULL,11,4),
(2,'러닝크루 들어가볼까 하는데 어떠세요?','혼자 뛰다 보니 슬슬 동기부여가 떨어져서 러닝크루 가입을 고민 중입니다.\n처음 가면 어색하지는 않은지, 실력 차이 많이 나면 민폐인지 궁금합니다.','127.0.0.1',NULL,27,9),
(2,'10km 완주 목표인데 신발 추천 부탁드려요','지금은 그냥 캐주얼 운동화로 5km 정도만 가볍게 뛰고 있습니다.\n무릎 부담 덜한 러닝화 브랜드/모델 추천해주시면 감사하겠습니다.','127.0.0.1',NULL,19,9),
(2,'출퇴근 러닝 해보신 분 계세요?','회사까지 5km 정도 거리인데, 주 1~2회는 러닝으로 출퇴근 해볼까 고민 중입니다.\n샤워, 짐 보관 같은 현실적인 팁 알려주시면 좋겠어요.','127.0.0.1',NULL,13,9),
(10,'로드 입문인데 클릿페달 바로 가도 될까요?','자전거는 자출용 미니벨로만 타다가 이번에 로드를 하나 들이려고 합니다.\n클릿이 편하다고들 하는데, 입문자도 바로 적응 가능할까요?','127.0.0.1',NULL,16,10),
(10,'대구 근교 주말 라이딩 코스 추천 부탁드려요','주말에 40~60km 정도 타기 좋은 코스 있을까요?\n차少+풍경 좋은 코스면 더 좋습니다.','127.0.0.1',NULL,21,10),
(5,'헬멧/라이트 같은 자전거 안전장비 필수템 뭐가 있을까요?','자출을 시작해보려고 하는데, 헬멧 말고도 꼭 챙겨야 할 안전 장비들이 있을까요?','127.0.0.1',NULL,8,10),
(11,'3분할 운동 루틴 이렇게 짜도 괜찮을까요?','월: 가슴/삼두, 수: 등/이두, 금: 하체/어깨 이렇게 3분할로 생각 중입니다.\n헬린이라서 세트 수나 볼륨 감이 안 오는데 피드백 부탁드립니다.','127.0.0.1',NULL,34,11),
(11,'PT 꼭 받아야 할까요? 혼자 유튜브 보고 해도 될지 고민입니다.','헬스장 등록만 해두고 제대로 못 가는 전형적인 3일 열정형입니다.\nPT 한 달 정도는 받아보는 게 나을까요, 아니면 그냥 프로그램만 짜서 혼자 해도 될까요?','127.0.0.1',NULL,22,11),
(11,'데드리프트 할 때 허리 통증… 자세 문제일까요?','무게를 많이 올린 건 아닌데, 데드하고 나면 허리가 뻐근하게 아픕니다.\n자세를 어떻게 점검해야 하는지 팁 있으면 알려주세요.','127.0.0.1',NULL,17,11),
(8,'요가 초보인데 집에서 유튜브만으로 시작해도 될까요?','스트레칭 겸 요가를 해보고 싶은데, 요가원 다니기보다는 집에서 유튜브 보고 따라하는 걸로 시작해볼까 합니다.\n자세 교정이 안 되면 부상 위험이 있을까요?','127.0.0.1',NULL,14,12),
(8,'아침 요가 루틴 추천해주세요','출근 전에 10~15분 정도 할 수 있는 가벼운 요가 루틴 추천 부탁드립니다.\n허리랑 어깨가 자주 뭉치는 편입니다.','127.0.0.1',NULL,9,12),
(8,'명상 요가 해보신 분 계신가요?','요가랑 명상을 같이 하는 프로그램이 있던데, 실제로 해보신 분들 경험이 궁금합니다.\n집중력이나 수면에 도움이 되셨나요?','127.0.0.1',NULL,7,12),
(9,'접영 배우고 싶은데 크롤이랑 평영만 할 줄 아는 상태입니다.','접영이 그렇게 힘들다는데도 궁금하네요.\n지금 단계에서 접영 배우는 게 무리일까요, 아니면 크롤/평영 더 다지고 가야 할까요?','127.0.0.1',NULL,12,15),
(9,'성인 수영 초급반 첫날에 보통 뭐 하나요?','수영 배우는 건 처음이라 옷부터 뭘 가져가야 할지 모르겠습니다.\n첫 수업 때 진행 방식이랑 준비물 알려주실 분 계신가요?','127.0.0.1',NULL,20,15),
(9,'오전/저녁 중 언제 수영하는 게 더 좋나요?','회사 다니면서 수영 병행해 보려고 하는데, 피곤함이나 컨디션 관리 측면에서 오전/저녁 중 뭐가 나을지 고민입니다.','127.0.0.1',NULL,10,15);
INSERT INTO reply (board_idx, mem_idx, reply_content, reply_ip, reply_is_deleted, reply_ref, reply_step, reply_depth) VALUES
(2,2,'입문이시면 중고 풀세트 하나 구해서 1~2년 써보시고 기변하는 걸 추천드려요. 처음엔 브랜드보단 스윙 만드는 게 더 중요하더라구요.','127.0.0.1','N',1,1,0),
(2,11,'동의합니다. 드라이버/아이언 다 새 제품으로 맞추면 금방 후회할 수도 있어서, 중고로 무난한 브랜드부터 시작해 보세요.','127.0.0.1','N',2,2,0),
(3,3,'아이언 정확도가 문제라면, 스크린보다는 연습장 가서 7번 아이언 하나로 거리/탄도 맞추는 연습만 한 달 해보셔도 체감이 올 거예요.','127.0.0.1','N',3,1,0),
(3,7,'필드보다 스크린 스코어가 잘 나오긴 하니까, 목표를 80대 초반이 아니라 90 꾸준히 유지부터 잡는 것도 좋아요. 꾸준함이 답입니다.','127.0.0.1','N',4,2,0),
(7,5,'러닝크루 이미 2년째 활동 중인데, 실력 차이 크게 신경 안 쓰셔도 됩니다. 본인 페이스대로 뛰도록 배려해주는 크루인지가 더 중요해요.','127.0.0.1','N',5,1,0),
(7,10,'처음엔 어색한데 두세 번만 나가면 금방 친해지더라구요. 단, 기록 위주 크루인지, 친목 위주인지 성격은 꼭 보고 들어가세요.','127.0.0.1','N',6,2,0),
(8,4,'무릎 부담 줄이려면 쿠션 좋은 모델로 가는 게 좋아요. 아식스나 호카 같은 브랜드 입문용 많이들 쓰십니다.','127.0.0.1','N',7,1,0),
(8,2,'발볼 넓으시면 반 치수 크게 신거나, 실제 매장에서 꼭 신어보고 사세요. 온라인 후기만 믿고 사면 피곤해집니다 ㅠㅠ','127.0.0.1','N',8,2,0),
(13,9,'3분할 구성이 무난하긴 한데, 어깨를 하체랑 같이 하면 생각보다 힘들 수 있어요. 하체/어깨를 나누거나, 어깨를 가슴날에 조금 섞어도 좋습니다.','127.0.0.1','N',9,1,0),
(13,11,'운동 시작한 지 얼마 안 되셨다면, 처음 한 달은 전신 루틴로 기본기 다지고 3분할로 넘어가는 것도 추천드립니다.','127.0.0.1','N',10,2,0),
(14,3,'본인이 스스로 루틴 짜서 꾸준히 할 수 있는 타입이면 PT 없이도 충분하지만, 전혀 감이 없으면 최소 10회 정도는 받아보시는 걸 추천해요.','127.0.0.1','N',11,1,0),
(14,8,'저는 PT 한 달 해보고, 동작만 익힌 다음에 혼자 운동 중인데 이 조합이 괜찮았어요. 기간을 정해서 써보는 느낌이 좋더라구요.','127.0.0.1','N',12,2,0),
(16,7,'완전 초보라면 처음 1~2개월은 요가원에서 기본 자세 배워두는 걸 추천드려요. 그 이후에 유튜브로 혼자 해도 훨씬 안전합니다.','127.0.0.1','N',13,1,0),
(16,2,'집에서 할 땐 무리해서 끝까지 따라가기보다, 통증 느껴지면 바로 풀어주는 게 중요해요. 특히 허리/목 조심하세요.','127.0.0.1','N',14,2,0),
(20,6,'첫날에는 물 적응이랑 호흡 연습 정도만 하실 거라 너무 긴장 안 하셔도 됩니다. 수모, 수경, 수영복 정도만 준비하시면 돼요.','127.0.0.1','N',15,1,0),
(20,9,'샤워용 슬리퍼 하나 챙기시면 편하고, 귀에 물 자주 차는 편이면 귀마개도 있으면 좋아요.','127.0.0.1','N',16,2,0);
