INSERT INTO auction (buyer_idx,item_category_idx,auction_thumbnail_img,auction_title,auction_desc,auction_target_price,auction_view_count,auction_start_at,auction_end_at,auction_decision_deadline,auction_status_idx,auction_regdate,auction_moddate,auction_is_deleted,auction_deldate) VALUES
(2,5,'/images/auction/fit_dm.png','입문용 스쿼트 랙 + 바벨 세트 구해요! 🏋️','이제 막 홈짐 시작하려는 헬린이입니다. 아파트라 너무 크지 않은 미니 랙이나 분리형 랙이었으면 좋겠어요. 바벨은 탄력봉 아니어도 되니까 저렴하게 넘겨주실 판매자님 찾습니다!',200000,0,NOW(),NOW() + INTERVAL 5 DAY,NOW() + INTERVAL 7 DAY,1,NOW(),NULL,'N',NULL),
(3,5,'/images/auction/fit_dm2.png','요가매트 8mm 이상 두꺼운 거 파실 분? 🧘','무릎이 아파서 아주 푹신하고 두꺼운 TPE 소재 요가매트 찾습니다. 사용감 조금 있어도 괜찮으니까 찢어진 곳만 없으면 돼요!',100000,0,NOW(),NOW() + INTERVAL 4 DAY,NOW() + INTERVAL 6 DAY,1,NOW(),NULL,'N',NULL),
(4,1,'/images/auction/ball_dm.png','층간소음 없는 실내용 농구공 구해요! 🏀','밤에도 집에서 드리블 연습하고 싶어서 저소음 공 찾고 있어요! 7호 사이즈면 좋겠고, 상태 깨끗한 녀석으로 픽 하겠습니다!',50000,0,NOW(),NOW() + INTERVAL 4 DAY,NOW() + INTERVAL 7 DAY,1,NOW(),NULL,'N',NULL),
(5,2,'/images/auction/ra_dm.png','입문용 요넥스 배드민턴 라켓(경량) 구합니다 🏸','손목이 약해서 4U~5U 정도의 가벼운 라켓 찾아요. 거트(줄) 새로 안 갈아도 바로 쓸 수 있는 상태면 더 좋습니다!',100000,0,NOW(),NOW() + INTERVAL 6 DAY,NOW() + INTERVAL 8 DAY,1,NOW(),NULL,'N',NULL),
(6,3,'/images/auction/pro_dm.png','러닝용 무릎 니슬리브 1세트 구함 (M사이즈) 🏃','무릎 지지력이 짱짱한 제품 찾아요! 세탁해도 냄새 안 나고 늘어남 없는 S급 상태였으면 좋겠습니다.',60000,0,NOW(),NOW() + INTERVAL 4 DAY,NOW() + INTERVAL 5 DAY,1,NOW(),NULL,'N',NULL),
(7,4,'/images/auction/sh_dm.png','나이키 에어줌 페가수스 러닝화 (240mm) 👟','조깅 시작해보려고 해요! 핑크나 화이트 컬러 들어간 디자인 좋아합니다. 바닥창 거의 안 닳은 새거 같은 중고 부탁드려요!',100000,0,NOW(),NOW() + INTERVAL 6 DAY,NOW() + INTERVAL 8 DAY,1,NOW(),NULL,'N',NULL),
(8,5,'/images/auction/fit_dm3.png','멜킨 스쿼트 머신 (화이트 에디션) 구해요! 🏋️','거실 인테리어 해치지 않는 깔끔한 화이트 컬러 스쿼트 머신 삽니다! 사용감 적고 발등 스펀지 짱짱한 걸로 보내주실 분?',100000,0,NOW(),NOW() + INTERVAL 3 DAY,NOW() + INTERVAL 5 DAY,1,NOW(),NULL,'N',NULL),
(9,6,'/images/auction/out_dm.png','감성 캠핑용 루미에르 랜턴 구합니다 🕯️','캠핑 밤을 샤방샤방하게 밝혀줄 가스 랜턴 찾아요! 유리 갓에 금 안 가고 케이스까지 풀세트로 있으신 분 찾습니다.',50000,0,NOW(),NOW() + INTERVAL 5 DAY,NOW() + INTERVAL 7 DAY,1,NOW(),NULL,'N',NULL),
(10,7,'/images/auction/sw_dm.png','미즈노 엑셀아이 수경 (노패킹/미러) 🏊','눈 자국 덜 남는 노패킹 수경 찾아요! 렌즈에 기스 없는 거 선호하고, 컬러는 화려할수록 좋습니다.',50000,0,NOW(),NOW() + INTERVAL 2 DAY,NOW() + INTERVAL 4 DAY,1,NOW(),NULL,'N',NULL),
(11,8,'/images/auction/ac_dm.png','가민 스마트워치 충전 케이블(정품) 급구! ⚡','충전기를 잃어버려서 운동 기록을 못 하고 있어요 ㅠㅠ 정품 케이블 단선 안 된 걸로 빨리 보내주실 판매자님 찾습니다!',30000,0,NOW(),NOW() + INTERVAL 7 DAY,NOW() + INTERVAL 9 DAY,1,NOW(),NULL,'N',NULL),
(2,1,'/images/auction/ball_dm1.png','파스텔 테니스공 1캔(4구) 구해요! 🎾','테니스 코트에서도 예쁨을 포기할 수 없는 테린이입니다! 핑크나 민트색 솜사탕 같은 파스텔톤 테니스공 찾고 있어요!',25000,0,NOW(),NOW() + INTERVAL 5 DAY,NOW() + INTERVAL 7 DAY,1,NOW(),NULL,'N',NULL),
(2,2,'/images/auction/ra_dm2.png','테일러메이드 스텔스2 여성용 드라이버 12도 구해요! ⛳','드라이버 비거리가 안 나와서 고민인 골린이입니다. 테일러메이드 스텔스2 모델로 구하고 있고, 샤프트는 L이었으면 좋겠어요!',450000,0,NOW(),NOW() + INTERVAL 5 DAY,NOW() + INTERVAL 7 DAY,1,NOW(),NULL,'N',NULL),
(3,8,'/images/auction/ac_dm2.png','출퇴근용 퀄리스포츠 Q3 미니 전기자전거 찾습니다! 🚲','왕복 10km 출퇴근용으로 타려고 해요. 배터리 상태 양호하고 브레이크 밀림 없는 녀석으로 구합니다!',800000,0,NOW(),NOW() + INTERVAL 4 DAY,NOW() + INTERVAL 6 DAY,1,NOW(),NULL,'N',NULL),
(4,6,'/images/auction/out_dm2.png','[유찰] 노르디스크 아스가르드 12.6 면텐트 구함 ⛺','감성 캠핑의 끝판왕 아스가르드 12.6 모델 구해요. 곰팡이 없고 시즈닝 잘 된 녀석으로 픽 하겠습니다!',900000,15,NOW() - INTERVAL 10 DAY,NOW() - INTERVAL 5 DAY,NOW() - INTERVAL 3 DAY,4,NOW() - INTERVAL 10 DAY,NULL,'N',NULL),
(5,1,'/images/auction/ball_dm2.png','[취소] 미즈노 프로 내야수용 글러브 구해요 ⚾','캐치볼용으로 쓸 미즈노 프로 등급 글러브 찾습니다. 가급적 길들이기 완료된 제품 선호해요!',300000,8,NOW() - INTERVAL 2 DAY,NOW() - INTERVAL 1 DAY,NOW() + INTERVAL 1 DAY,5,NOW() - INTERVAL 2 DAY,NULL,'N',NULL);
