(@la+1,2,@local_item+1,90000,1,'유니콘 갤럭시 요가매트 새것입니다! 개봉만 했고 사용감 전혀 없어요. 💖',1,NOW(),NULL),
(@la+3,11,@local_item+2,90000,1,'거트 작업 새로 마친 상태이며, 헤드 부분 기스 없는 최상급 컨디션입니다.',1,NOW(),NULL),
(@la+3,2,@local_item+3,80000,1,'파스텔 민트 색상이 아주 예쁜 모델입니다. 셔틀콕 2알 서비스로 동봉해 드립니다.',1,NOW(),NULL),
(@la+3,10,@local_item+4,100000,1,'선물 받고 보관만 한 미개봉 새상품입니다. 보증서 포함 풀패키지로 발송해 드립니다.',1,NOW(),NULL),
(@la+5,10,@local_item+5,90000,1,'실내 헬스장에서 딱 2번 착용했습니다. 아웃솔 마모 전혀 없고 새제품급 상태입니다.',1,NOW(),NULL),
(@la+5,3,@local_item+6,80000,1,'전문 세탁 완료하여 깨끗합니다. 기능상 하자 전혀 없으니 편하게 신으실 분 추천합니다.',1,NOW(),NULL);
